# Mathematical utility functions and constants

PI: float = 3.14159
E: float = 2.71828

def square(x: float) -> float:
    return x * x

def cube(x: float) -> float:
    return x * x * x

def clamp(value: float, min_val: float, max_val: float) -> float:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

